78: 		if s, ok := grpcstatus.FromError(err); ok && s.Code() == grpccodes.Canceled {
79: 			return nil, plugins.ErrPluginRequestCanceledErrorBase.Errorf("client: query data request canceled: %w", err)
80: 		}
